/**
 * @summary Record a payment for a package owner
 */
export const getEnregistrerPaiementUrl = (id: number) => {
  return `/api/colis-proprietaires/${id}/paiements`;
};

export const enregistrerPaiement = async (
  id: number,
  createPaiementRequest: CreatePaiementRequest,
  options?: RequestInit,
): Promise<Paiement> => {
  return customFetch<Paiement>(getEnregistrerPaiementUrl(id), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(createPaiementRequest),
  });
};

export const getEnregistrerPaiementMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof enregistrerPaiement>>,
    TError,
    { id: number; data: BodyType<CreatePaiementRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof enregistrerPaiement>>,
  TError,
  { id: number; data: BodyType<CreatePaiementRequest> },
  TContext
> => {
  const mutationKey = ["enregistrerPaiement"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof enregistrerPaiement>>,
    { id: number; data: BodyType<CreatePaiementRequest> }
  > = (props) => {
    const { id, data } = props ?? {};

    return enregistrerPaiement(id, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type EnregistrerPaiementMutationResult = NonNullable<
  Awaited<ReturnType<typeof enregistrerPaiement>>
>;
export type EnregistrerPaiementMutationBody = BodyType<CreatePaiementRequest>;
export type EnregistrerPaiementMutationError = ErrorType<unknown>;

/**
 * @summary Record a payment for a package owner
 */
export const useEnregistrerPaiement = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof enregistrerPaiement>>,
    TError,
    { id: number; data: BodyType<CreatePaiementRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof enregistrerPaiement>>,
  TError,
  { id: number; data: BodyType<CreatePaiementRequest> },
  TContext
> => {
  return useMutation(getEnregistrerPaiementMutationOptions(options));
};

/**
 * @summary List all outstanding debts
 */
export const getListDettesUrl = (params?: ListDettesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/dettes?${stringifiedParams}`
    : `/api/dettes`;
};

export const listDettes = async (
  params?: ListDettesParams,
  options?: RequestInit,
): Promise<DetteDetail[]> => {
  return customFetch<DetteDetail[]>(getListDettesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListDettesQueryKey = (params?: ListDettesParams) => {
  return [`/api/dettes`, ...(params ? [params] : [])] as const;
};

export const getListDettesQueryOptions = <
  TData = Awaited<ReturnType<typeof listDettes>>,
  TError = ErrorType<unknown>,
>(
  params?: ListDettesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listDettes>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListDettesQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listDettes>>> = ({
    signal,
  }) => listDettes(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listDettes>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListDettesQueryResult = NonNullable<
  Awaited<ReturnType<typeof listDettes>>
>;
export type ListDettesQueryError = ErrorType<unknown>;

/**
 * @summary List all outstanding debts
 */

export function useListDettes<
  TData = Awaited<ReturnType<typeof listDettes>>,
  TError = ErrorType<unknown>,
>(
  params?: ListDettesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listDettes>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListDettesQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

